def ensure_certs_directory():
    """Create certs directory and generate self-signed certificates if they don't exist."""
    os.makedirs("certs", exist_ok=True)

    cert_file = IDP_CONFIG["certificate_file"]
    key_file = IDP_CONFIG["private_key_file"]

    if not os.path.exists(cert_file) or not os.path.exists(key_file):
        print("Generating self-signed certificate for IdP...")
        from cryptography import x509
        from cryptography.x509.oid import NameOID
        from cryptography.hazmat.primitives import hashes, serialization
        from cryptography.hazmat.primitives.asymmetric import rsa

        private_key = rsa.generate_private_key(
            public_exponent=65537,
            key_size=2048,
        )

        subject = issuer = x509.Name([
            x509.NameAttribute(NameOID.COUNTRY_NAME, "US"),
            x509.NameAttribute(NameOID.STATE_OR_PROVINCE_NAME, "Internal"),
            x509.NameAttribute(NameOID.ORGANIZATION_NAME, "Internal IdP"),
            x509.NameAttribute(NameOID.COMMON_NAME, "idp.internal.example.com"),
        ])

        cert = (
            x509.CertificateBuilder()
            .subject_name(subject)
            .issuer_name(issuer)
            .public_key(private_key.public_key())
            .serial_number(x509.random_serial_number())
            .not_valid_before(datetime.now(timezone.utc))
            .not_valid_after(datetime.now(timezone.utc) + timedelta(days=3650))
            .add_extension(
                x509.SubjectAlternativeName([
                    x509.DNSName("idp.internal.example.com"),
                    x509.DNSName("localhost"),
                ]),
                critical=False,
            )
            .sign(private_key, hashes.SHA256())
        )

        with open(key_file, "wb") as f:
            f.write(private_key.private_bytes(
                encoding=serialization.Encoding.PEM,
                format=serialization.PrivateFormat.TraditionalOpenSSL,
                encryption_algorithm=serialization.NoEncryption(),
            ))

        with open(cert_file, "wb") as f:
            f.write(cert.public_bytes(serialization.Encoding.PEM))

        print(f"Certificate and key generated: {cert_file}, {key_file}")


def load_certificate():
    """Load the IdP certificate."""
    with open(IDP_CONFIG["certificate_file"], "r") as f:
        cert = f.read()
    # Strip PEM headers for embedding in XML
    cert_clean = cert.replace("-----BEGIN CERTIFICATE-----", "")
    cert_clean = cert_clean.replace("-----END CERTIFICATE-----", "")
    cert_clean = cert_clean.replace("\n", "").replace("\r", "").strip()
    return cert, cert_clean


def load_private_key():
    """Load the IdP private key."""
    with open(IDP_CONFIG["private_key_file"], "r") as f:
        return f.read()


def generate_id():
    """Generate a unique SAML ID."""
    return "_" + uuid.uuid4().hex


def get_timestamp(offset_seconds=0):
    """Generate an ISO 8601 timestamp."""
    dt = datetime.now(timezone.utc) + timedelta(seconds=offset_seconds)
    return dt.strftime("%Y-%m-%dT%H:%M:%SZ")


def parse_authn_request(encoded_request):
    """Parse and validate an incoming SAML AuthnRequest."""
    try:
        decoded = base64.b64decode(encoded_request)
        # Try to decompress (deflate encoding)
        try:
            import zlib
            decoded = zlib.decompress(decoded, -15)
        except (zlib.error, Exception):
            pass

        root = etree.fromstring(decoded)

        authn_request = {
            "id": root.get("ID"),
            "issuer": None,
            "acs_url": root.get("AssertionConsumerServiceURL"),
            "destination": root.get("Destination"),
            "protocol_binding": root.get("ProtocolBinding"),
            "name_id_policy_format": None,
        }

        # Extract Issuer
        issuer_elem = root.find("{urn:oasis:names:tc:SAML:2.0:assertion}Issuer")
        if issuer_elem is not None:
            authn_request["issuer"] = issuer_elem.text

        # Extract NameIDPolicy
        name_id_policy = root.find("{urn:oasis:names:tc:SAML:2.0:protocol}NameIDPolicy")
        if name_id_policy is not None:
            authn_request["name_id_policy_format"] = name_id_policy.get("Format")

        return authn_request

    except Exception as e:
        print(f"Error parsing AuthnRequest: {e}")
        return None


